import{_ as o,c as s,ah as t,o as i}from"./chunks/framework.BjDJcZmr.js";const h=JSON.parse('{"title":"Semantic Versioning","description":"语义化版本 (Semantic Versioning, 简称 SemVer) 是一种版本号命名规范，用于清晰地表达软件版本的变化及其兼容性。采用 主版本号.次版本号.修订号 的格式","frontmatter":{"date":"2025-07-03T00:00:00.000Z","title":"Semantic Versioning","category":"Guilty Crown","tags":["git"],"description":"语义化版本 (Semantic Versioning, 简称 SemVer) 是一种版本号命名规范，用于清晰地表达软件版本的变化及其兼容性。采用 主版本号.次版本号.修订号 的格式"},"headers":[],"relativePath":"posts/semantic-versioning.md","filePath":"posts/semantic-versioning.md"}'),l={name:"posts/semantic-versioning.md"};function n(r,e,a,c,g,d){return i(),s("div",null,e[0]||(e[0]=[t('<h1 id="语义化版本" tabindex="-1">语义化版本 <a class="header-anchor" href="#语义化版本" aria-label="Permalink to &quot;语义化版本&quot;">​</a></h1><details class="details custom-block"><summary>目录</summary><nav class="table-of-contents"><ul><li><a href="#什么是语义化版本">什么是语义化版本</a><ul><li><a href="#举个例子">举个例子</a></li></ul></li><li><a href="#faq">FAQ</a></li><li><a href="#references">References</a></li></ul></nav></details><h2 id="什么是语义化版本" tabindex="-1"><strong>什么是语义化版本</strong> <a class="header-anchor" href="#什么是语义化版本" aria-label="Permalink to &quot;**什么是语义化版本**&quot;">​</a></h2><p>语义化版本是一种描述软件的方式，使用一组规则描述版本的变化，采用 <strong>主版本号</strong>.<strong>次版本号</strong>.<strong>修订号</strong> 的格式</p><ul><li><p><strong>主版本号 (Major)</strong>：当软件进行不兼容的 API 变更 (breaking changes)，主版本号递增次版本号和修订号重置为 0</p></li><li><p><strong>次版本号 (Minor)</strong>：当软件添加了新功能，但保持向后兼容时，次版本号递增，修订号重置为 0</p></li><li><p><strong>修订号 (Patch)</strong>：当软件进行向后兼容的 bug 修复或小更新，修订号递增</p></li><li><p><strong>先行版本号</strong>及版本编译信息可以加到 <code>Major.Minor.Patch</code> 之后作延申</p></li></ul><h3 id="举个例子" tabindex="-1"><strong>举个例子</strong> <a class="header-anchor" href="#举个例子" aria-label="Permalink to &quot;**举个例子**&quot;">​</a></h3><p>假设当前有一个版本号为 <code>1.0.0</code> 的软件包供给外部软件调用，当前软件包中有一个函数 <code>example(a: string, b: number): string {}</code></p><ul><li><code>example</code> 函数体存在 bug，修复 bug 后未在软件中引入新的 API，该函数仍能实现预期的功能。这就是仅进行 bug 修复，<strong>未添加新功能，未发生不兼容的 API 修改</strong>，版本号变更为 <code>1.0.1</code></li><li>软件包中新增了 <code>example</code> 的函数重载，如：<code>example(a: string, b: number, c?: boolean): string {}</code>，用户原有的调用依旧返回预期结果，当用户的 <code>example</code> 函数传入 <code>c</code> 参数时，返回值发生变化。<strong>新增了一个函数重载的功能，未发生不兼容的 API 修改</strong>，版本号变更为 <code>1.1.0</code></li><li><code>example</code> 函数新增了一个参数，如：<code>example(a: string, b: number, c: boolean): string {}</code>，用户<strong>原有的调用会报错提示缺少参数，这时就发生了不兼容的 API 修改</strong>，版本号变更为 <code>2.0.0</code></li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><ul><li><p><strong>如何处理初始阶段的版本</strong></p><ul><li>软件的主版本号为 <code>0.y.z</code> 是一种特殊状态，这意味着该软件处于开发初始阶段，一切都可能随时被改变</li><li>最简单的做法是以 <code>0.1.0</code> 作为初始化开发版本，并在后续的每次发行时递增次版本号</li></ul></li><li><p><strong>如何判断发布 <code>1.0.0</code> 的时机</strong></p><ul><li>当软件被部署到生产环境中开始被正式使用，它应该已经达到了 <code>1.0.0</code></li><li>此时的软件已经有了一系列稳定的 API 在被使用者依赖，并开始需要考虑向后兼容的问题</li></ul></li><li><p><strong><code>v.1.2.3</code> 是语义版本吗</strong></p><ul><li><p>不是。<code>v.1.2.3</code> 是标签名称，<code>1.2.3</code> 是语义版本</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tag</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> v1.2.3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Release version 1.2.3&quot;</span></span></code></pre></div></li></ul></li><li><p><strong>如何决定版本的优先级</strong>：判断优先级时，必须把本依序拆分为<strong>主版本号</strong>、<strong>次版本号</strong>、<strong>修订号</strong>及<strong>先行版本号</strong>后进行比较</p><ul><li><strong>正式版本</strong>：依次比较<strong>主版本号</strong>、<strong>次版本号</strong>、<strong>修订号</strong>，数字较大的优先级较高 (如：<code>2.0.0</code> &gt; <code>1.0.0</code>)</li><li><strong>相同版本</strong>：<strong>正式版本</strong>的优先级高于<strong>先行版本</strong> (如：<code>1.0.0</code> &gt; <code>1.0.0-alpha</code>)</li><li><strong>先行版本</strong>：先行版本也相同时，其优先级通过从左到右的每个被句点分隔的标识符来比较，直到找到差异值 <ul><li><strong>数字标识符</strong>：<strong>按照数值的高低比较</strong> (如：<code>1.0.0-alpha.5</code> &gt; <code>1.0.0-alpha.1</code>)</li><li><strong>字母</strong>：<strong>按照 ASCII 的顺序比较</strong> (如：<code>1.0.0-alpha.rc</code> &gt; <code>1.0.0-alpha.beta</code>)</li><li><strong>正式版本相同时，非数字标识符优先级更高</strong> (如：<code>1.0.0-alpha</code> &gt; <code>1.0.0-0</code>)</li><li><strong>先行标识符相同时，栏位较多的优先级更高</strong> (如：<code>1.0.0-alpha.1.0</code> &gt; <code>1.0.0-alpha.1</code>)</li></ul></li></ul></li><li><p><strong>这会阻碍快速开发和快速迭代吗</strong></p><ol><li><p>如果每天修改大量 API，那么应该继续使用 <code>0.y.z</code> 作为版本</p></li><li><p>或者在单独的分支开发下一个主版本</p></li></ol></li><li><p><strong>如果意外地将向后不兼容的更改发布为次要版本，怎么办</strong></p><ul><li>一旦违反了语义化版本控制规范，请立即修复问题并发布新的次要版本，纠正问题并恢复向后兼容性</li><li>修改已发布的版本是不可接受的，如果合适，记录违规版本并告知用户</li></ul></li><li><p><strong>如果不改变公共 API，而是更新自身的依赖</strong></p><ul><li>理论上它不影响公共 API，但仍需明确引入的依赖具有其自身的依赖项规范，确定更改是补丁级别、修复错误、还是引入新功能</li></ul></li><li><p><strong>如果无意间以不符合的版本更改方式更改了公共 API (Breaking Changes)</strong></p><ul><li>如果更改对预期造成巨大影响，那么需要进行一次主要版本发布 (即使这该被视为补丁分布)</li></ul></li><li><p><strong>如何处理<s>已弃用</s>的功能 (<s>弃用的公共 API</s>)</strong></p><ol><li>更新文档，告知用户相关变更</li><li>发布包含弃用内容的新次要版本，在新的主要版本完全移除相关功能之前，应该至少发布一个包含启用内容的次要版本，方便用户过渡到新 API</li></ol></li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://semver.org/lang/zh-CN/" target="_blank" rel="noreferrer">语义化版本 2.0</a></li></ul>',12)]))}const u=o(l,[["render",n]]);export{h as __pageData,u as default};
